#include <stdio.h>
#include <stdlib.h>

// Structure to represent a graph
typedef struct {
    int numNodes;
    int** adjList;
} Graph;

// Function to create a graph
Graph* createGraph(int numNodes) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    graph->numNodes = numNodes;
    graph->adjList = (int**) malloc(numNodes * sizeof(int*));
    for (int i = 0; i < numNodes; i++) {
        graph->adjList[i] = (int*) malloc(2 * sizeof(int));
        graph->adjList[i][0] = 0;
        graph->adjList[i][1] = 0;
    }
    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int u, int v) {
    int* temp = (int*) realloc(graph->adjList[u], (graph->adjList[u][0] + 2) * sizeof(int));
    graph->adjList[u] = temp;
    graph->adjList[u][graph->adjList[u][0] + 1] = v;
    graph->adjList[u][0]++;
    temp = (int*) realloc(graph->adjList[v], (graph->adjList[v][0] + 2) * sizeof(int));
    graph->adjList[v] = temp;
    graph->adjList[v][graph->adjList[v][0] + 1] = u;
    graph->adjList[v][0]++;
}

// Function to perform DFS
void dfs(Graph* graph, int node, int* visited) {
    visited[node] = 1;
    printf("%d ", node + 1);
    for (int i = 1; i <= graph->adjList[node][0]; i++) {
        if (!visited[graph->adjList[node][i]]) {
            dfs(graph, graph->adjList[node][i], visited);
        }
    }
}

int main() {
    int numNodes, numEdges;
    scanf("%d %d", &numNodes, &numEdges);
    Graph* graph = createGraph(numNodes);
    for (int i = 0; i < numEdges; i++) {
        int u, v;
        scanf("%d %d", &u, &v);
        addEdge(graph, u - 1, v - 1);
    }
    int* visited = (int*) malloc(numNodes * sizeof(int));
    for (int i = 0; i < numNodes; i++) {
        visited[i] = 0;
    }
    printf("DFS traversal: ");
    for (int i = 0; i < numNodes; i++) {
        if (!visited[i]) {
            dfs(graph, i, visited);
        }
    }
    return 0;
}

